import type { Question } from "./questions";

export const MEDICINE_QUESTIONS: Question[] = [
  // ── CARDIOLOGY ──────────────────────────────────────────────────────────────
  { id:5001, subject:"Medicine", stem:"First-line treatment for ST-elevation myocardial infarction (STEMI) within 12 hours of symptom onset is:", options:["Thrombolysis with streptokinase","Primary percutaneous coronary intervention (PCI)","Emergency CABG","IV heparin alone"], answer:1, explanation:"Primary PCI is the preferred reperfusion strategy for STEMI if available within 120 minutes of first medical contact. It achieves better outcomes than thrombolysis." },
  { id:5002, subject:"Medicine", stem:"The 'four pillars' of heart failure with reduced ejection fraction (HFrEF) therapy per ESC 2021/2023 guidelines are:", options:["ACEi/ARB/ARNI + Beta-blocker + MRA + Digoxin","ACEi/ARB/ARNI + Beta-blocker + MRA + SGLT2i","Beta-blocker + Diuretic + Aldosterone + Ivabradine","ARB + SGLT2i + Diuretic + Nitrate"], answer:1, explanation:"ESC 2021 guidelines mandate ACEi/ARB/ARNI + beta-blocker + MRA + SGLT2i (dapagliflozin/empagliflozin) for all HFrEF regardless of diabetes status." },
  { id:5003, subject:"Medicine", stem:"ECG finding pathognomonic of hyperkalaemia at serum K+ >6.5 mEq/L is:", options:["Prominent U waves","Peaked (tall tented) T waves","Prolonged QT interval","Delta waves"], answer:1, explanation:"Peaked symmetrical T waves are the earliest ECG sign of hyperkalaemia. As K+ rises further: PR prolongation → widened QRS → sine wave pattern → VF." },
  { id:5004, subject:"Medicine", stem:"Drug of choice for rate control in atrial fibrillation with pre-excitation (WPW syndrome) is:", options:["Digoxin","Verapamil","Procainamide","Adenosine"], answer:2, explanation:"Digoxin and verapamil are contraindicated in AF+WPW as they enhance accessory pathway conduction. Procainamide (or DC cardioversion) is used. Adenosine can cause VF." },
  { id:5005, subject:"Medicine", stem:"The P-wave in aVR during normal sinus rhythm is:", options:["Upright and biphasic","Inverted (negative)","Absent","Notched"], answer:1, explanation:"aVR faces the cavity of the heart; P wave (atrial depolarisation going away from aVR) appears inverted/negative in aVR during normal sinus rhythm." },
  { id:5006, subject:"Medicine", stem:"Troponin I begins to rise after acute MI within:", options:["1-2 hours","3-6 hours","12-24 hours","48-72 hours"], answer:1, explanation:"Cardiac troponin I rises 3-6 hours post-MI, peaks at 12-24 hours, and remains elevated for 7-10 days (useful for late presenters)." },
  { id:5007, subject:"Medicine", stem:"Most common cause of aortic stenosis in patients under 70 years in India is:", options:["Degenerative calcific","Bicuspid aortic valve","Rheumatic heart disease","Infective endocarditis"], answer:2, explanation:"Rheumatic heart disease remains the predominant cause of aortic stenosis in developing countries including India, affecting younger patients. Degenerative calcification dominates in the West/elderly." },
  { id:5008, subject:"Medicine", stem:"Dressler syndrome occurs after myocardial infarction typically at:", options:["24-48 hours","1-3 days","2-10 weeks","6-12 months"], answer:2, explanation:"Dressler syndrome (post-cardiac injury syndrome) is an autoimmune pericarditis occurring 2-10 weeks post-MI. Treated with NSAIDs/colchicine; steroids reserved for refractory cases." },
  { id:5009, subject:"Medicine", stem:"Which antihypertensive is absolutely contraindicated in bilateral renal artery stenosis?", options:["Amlodipine","ACE inhibitor","Beta-blocker","Alpha-blocker"], answer:1, explanation:"ACE inhibitors block angiotensin-II-mediated efferent arteriolar constriction that maintains GFR in bilateral RAS. Blocking this causes acute renal failure." },
  { id:5010, subject:"Medicine", stem:"The most common site of ventricular septal defect (VSD) is:", options:["Muscular","Inlet (AV canal type)","Perimembranous (membranous)","Outlet (supracristal)"], answer:2, explanation:"Perimembranous VSD accounts for 70-80% of all VSDs; it occurs at the membranous septum near the tricuspid valve and aortic valve." },
  { id:5011, subject:"Medicine", stem:"NYHA class III heart failure corresponds to:", options:["No symptoms at any activity","Symptoms with moderate exertion (climbing stairs)","Symptoms with minimal exertion (dressing)","Symptoms at rest"], answer:2, explanation:"NYHA III: marked limitation — comfortable at rest, symptoms (dyspnoea/angina) with less than ordinary activity (e.g., walking short distances, dressing)." },
  { id:5012, subject:"Medicine", stem:"'Machine-like' continuous murmur heard below left clavicle is characteristic of:", options:["ASD","VSD","PDA","Coarctation of aorta"], answer:2, explanation:"Patent ductus arteriosus produces a continuous 'machinery' murmur at the left upper sternal border/below left clavicle due to left-to-right shunting throughout cardiac cycle." },
  { id:5013, subject:"Medicine", stem:"Drug used for immediate chemical cardioversion of atrial flutter is:", options:["Amiodarone","Ibutilide","Digoxin","Verapamil"], answer:1, explanation:"Ibutilide (class III antiarrhythmic) is effective for chemical cardioversion of atrial flutter. Amiodarone is used for maintenance of sinus rhythm. Digoxin only controls rate." },
  { id:5014, subject:"Medicine", stem:"The most specific marker for myocardial damage is:", options:["CK-MB","Myoglobin","LDH","Troponin I"], answer:3, explanation:"Cardiac troponin I (cTnI) is highly specific for myocardial injury as it is expressed exclusively in cardiac muscle. Myoglobin and CK-MB can rise in skeletal muscle injury." },
  { id:5015, subject:"Medicine", stem:"Beck's triad of cardiac tamponade consists of:", options:["Hypotension + raised JVP + muffled heart sounds","Chest pain + fever + pericardial rub","Tachycardia + hypotension + pulmonary oedema","Cyanosis + clubbing + polycythaemia"], answer:0, explanation:"Beck's triad: hypotension (reduced cardiac output) + raised JVP (impaired venous return) + muffled heart sounds (fluid around heart)." },
  { id:5016, subject:"Medicine", stem:"Pulsus paradoxus is best described as:", options:["Pulse disappearing during systole","Fall in systolic BP >10 mmHg during inspiration","Rise in diastolic BP during expiration","Alternating strong and weak pulses"], answer:1, explanation:"Pulsus paradoxus: exaggerated fall in SBP >10 mmHg during inspiration, seen in cardiac tamponade, severe asthma, COPD exacerbation." },
  { id:5017, subject:"Medicine", stem:"Which class of antihypertensive is preferred in hypertension with CKD and proteinuria?", options:["Calcium channel blockers","Beta-blockers","ACE inhibitors/ARBs","Diuretics"], answer:2, explanation:"ACE inhibitors/ARBs reduce intraglomerular pressure, decrease proteinuria, and slow CKD progression. They are first-line for hypertension with diabetic or non-diabetic CKD+proteinuria." },
  { id:5018, subject:"Medicine", stem:"S3 gallop rhythm is best heard at:", options:["Aortic area with patient sitting forward","Apex with patient in left lateral position","Left sternal border with patient supine","Pulmonary area during expiration"], answer:1, explanation:"S3 (ventricular filling sound) is best heard at the apex with the bell of the stethoscope, with the patient in the left lateral decubitus position." },
  { id:5019, subject:"Medicine", stem:"Which valve lesion produces Austin Flint murmur?", options:["Mitral stenosis","Aortic stenosis","Aortic regurgitation","Tricuspid stenosis"], answer:2, explanation:"Austin Flint murmur: low-pitched mid-diastolic murmur at apex in severe aortic regurgitation, caused by regurgitant jet preventing full opening of the anterior mitral leaflet." },
  { id:5020, subject:"Medicine", stem:"Commonest cause of infective endocarditis in IV drug users is:", options:["Streptococcus viridans","Staphylococcus aureus","Enterococcus","HACEK organisms"], answer:1, explanation:"IV drug users have right-sided endocarditis predominantly, with Staphylococcus aureus being the most common organism (tricuspid valve most commonly affected)." },

  // ── RESPIRATORY ─────────────────────────────────────────────────────────────
  { id:5021, subject:"Medicine", stem:"GINA 2023 recommends which inhaler as the preferred reliever at Step 1 in adult asthma?", options:["SABA (salbutamol) alone","ICS-formoterol low dose (as-needed)","LABA alone","Ipratropium bromide"], answer:1, explanation:"GINA 2023 eliminates SABA-only treatment. Low-dose ICS-formoterol as-needed is now preferred at Step 1 to reduce severe exacerbations, even in mild asthma." },
  { id:5022, subject:"Medicine", stem:"GOLD classification of COPD is based on:", options:["FEV1/FVC ratio alone","Symptoms + exacerbation history + FEV1 (ABE groups)","CT scan findings","6-minute walk test"], answer:1, explanation:"GOLD 2023 uses the ABE system: Group A (low symptoms, 0-1 exacerbations), Group B (high symptoms, 0-1 exacerbations), Group E (≥2 exacerbations or 1 hospitalisation)." },
  { id:5023, subject:"Medicine", stem:"The drug that has replaced IV quinine as first-line treatment for severe malaria is:", options:["Artemether IM","IV Artesunate","Oral Artemether-lumefantrine","Chloroquine"], answer:1, explanation:"WHO 2023 guidelines recommend IV artesunate as first-line for severe P. falciparum malaria (superior to quinine in reducing mortality)." },
  { id:5024, subject:"Medicine", stem:"Horner syndrome on the right side with right-sided Pancoast tumour results in:", options:["Ptosis + mydriasis + anhidrosis","Ptosis + miosis + anhidrosis right face","Exophthalmos + lacrimation","Bilateral ptosis"], answer:1, explanation:"Horner syndrome: ptosis (superior tarsal muscle) + miosis (dilator pupillae) + anhidrosis ipsilateral face. Caused by interruption of sympathetic chain at T1 in Pancoast (superior sulcus) tumour." },
  { id:5025, subject:"Medicine", stem:"Light's criteria for exudative pleural effusion requires (any one of):", options:["Pleural LDH >200 IU/L","Pleural protein/serum protein ratio >0.5, OR pleural LDH/serum LDH ratio >0.6, OR pleural LDH >2/3 upper limit of serum normal","Pleural glucose <60 mg/dL","Pleural pH <7.2"], answer:1, explanation:"Light's criteria: exudate if pleural protein/serum protein >0.5, OR pleural LDH/serum LDH >0.6, OR pleural LDH >2/3 upper limit of normal serum LDH." },
  { id:5026, subject:"Medicine", stem:"'Tree-in-bud' pattern on HRCT chest is characteristic of:", options:["Pulmonary embolism","Endobronchial spread of tuberculosis","Sarcoidosis","Usual interstitial pneumonia (UIP)"], answer:1, explanation:"Tree-in-bud pattern on CT represents endobronchial spread of infection (classically TB, also atypical mycobacteria), showing centrilobular nodules connected by branching lines." },
  { id:5027, subject:"Medicine", stem:"Biologic agent of choice for severe eosinophilic asthma uncontrolled on high-dose ICS+LABA is:", options:["Omalizumab (anti-IgE)","Mepolizumab (anti-IL-5)","Benralizumab (anti-IL-5Rα)","Dupilumab (anti-IL-4Rα)"], answer:1, explanation:"Mepolizumab (anti-IL-5) reduces eosinophil counts and is first-line biologic for severe eosinophilic asthma with blood eosinophils ≥300 cells/μL." },
  { id:5028, subject:"Medicine", stem:"Hampton's hump on chest X-ray is seen in:", options:["Pneumothorax","Pulmonary embolism with infarction","Lobar pneumonia","Pleural effusion"], answer:1, explanation:"Hampton's hump: wedge-shaped peripheral opacity with the base on the pleura, seen in pulmonary infarction from PE. Westermark sign (oligaemia) is another CXR sign of PE." },
  { id:5029, subject:"Medicine", stem:"Serum ACE level is elevated in:", options:["Pulmonary embolism","Sarcoidosis","Mesothelioma","Extrinsic allergic alveolitis"], answer:1, explanation:"Serum ACE is elevated in sarcoidosis (produced by epithelioid cells of granulomas). Useful for monitoring disease activity, though not specific enough for diagnosis." },
  { id:5030, subject:"Medicine", stem:"CURB-65 score is used to assess severity of:", options:["COPD exacerbation","Community-acquired pneumonia","Pulmonary embolism","Pleural effusion"], answer:1, explanation:"CURB-65: Confusion, Urea >7, Respiratory rate ≥30, BP <90/60, age ≥65. Score 0-1: home treatment; 2: hospital; ≥3: ICU consideration in CAP." },
  { id:5031, subject:"Medicine", stem:"Gold standard diagnostic test for pulmonary embolism is:", options:["D-dimer level","Ventilation-perfusion scan","CT pulmonary angiography (CTPA)","Lower limb Doppler"], answer:2, explanation:"CTPA is the gold standard for PE diagnosis — high sensitivity and specificity. D-dimer is used for exclusion (high sensitivity, low specificity). V/Q scan used when CT contraindicated." },
  { id:5032, subject:"Medicine", stem:"Cheyne-Stokes breathing is characterised by:", options:["Rapid deep breathing","Alternating periods of hyperpnoea and apnoea","Single prolonged expiration","Irregular breathing with sighs"], answer:1, explanation:"Cheyne-Stokes: cyclic crescendo-decrescendo breathing with periods of apnoea, seen in advanced heart failure, stroke, brainstem lesions, high altitude." },
  { id:5033, subject:"Medicine", stem:"In obstructive sleep apnoea, the investigation of choice is:", options:["CT scan of neck","Polysomnography","Arterial blood gas","Chest X-ray"], answer:1, explanation:"Polysomnography (sleep study) is the gold standard for diagnosing OSA — measures sleep stages, airflow, oxygen saturation, EEG, EMG during sleep." },
  { id:5034, subject:"Medicine", stem:"Spirometry pattern in restrictive lung disease shows:", options:["FEV1/FVC <70% with normal FVC","Normal FEV1/FVC (>70%) with reduced FVC and TLC","Increased RV with air trapping","Reduced DLCO with normal spirometry"], answer:1, explanation:"Restrictive pattern: normal or increased FEV1/FVC ratio (>70%) with reduced FVC, TLC, and RV. Seen in pulmonary fibrosis, pleural effusion, obesity, neuromuscular disease." },
  { id:5035, subject:"Medicine", stem:"Roflumilast is used in COPD as:", options:["Bronchodilator","Phosphodiesterase-4 inhibitor to reduce exacerbations in FEV1 <50% with chronic bronchitis phenotype","Mucolytic agent","Biologic therapy"], answer:1, explanation:"Roflumilast (oral PDE-4 inhibitor) reduces exacerbations in COPD patients with FEV1 <50% and chronic bronchitis phenotype who remain symptomatic on dual bronchodilators." },

  // ── GASTROENTEROLOGY ────────────────────────────────────────────────────────
  { id:5036, subject:"Medicine", stem:"Most common cause of upper GI bleeding in adults is:", options:["Mallory-Weiss tear","Oesophageal varices","Peptic ulcer disease","Gastric cancer"], answer:2, explanation:"Peptic ulcer disease (duodenal ulcer > gastric ulcer) is the most common cause of upper GI bleeding worldwide, accounting for ~50% of cases." },
  { id:5037, subject:"Medicine", stem:"Child-Pugh score for liver cirrhosis includes all EXCEPT:", options:["Serum albumin","Bilirubin","Ascites","Serum creatinine"], answer:3, explanation:"Child-Pugh score: bilirubin, albumin, PT/INR, ascites, hepatic encephalopathy — 5 parameters. Creatinine is part of MELD score, not Child-Pugh." },
  { id:5038, subject:"Medicine", stem:"First-line treatment for spontaneous bacterial peritonitis (SBP) is:", options:["Cefotaxime IV","Metronidazole IV","Ampicillin + Gentamicin","Amikacin"], answer:0, explanation:"IV cefotaxime (3rd generation cephalosporin) for 5 days is first-line for SBP. Human albumin (1.5 g/kg day 1, 1 g/kg day 3) is given to prevent hepatorenal syndrome." },
  { id:5039, subject:"Medicine", stem:"Hepatic encephalopathy is treated with:", options:["Neomycin IV","Lactulose + Rifaximin","Metronidazole + Vancomycin","Protein restriction alone"], answer:1, explanation:"Lactulose (reduces ammonia production/absorption) + Rifaximin (non-absorbable antibiotic reducing gut bacteria) is standard for hepatic encephalopathy treatment." },
  { id:5040, subject:"Medicine", stem:"'String sign' on barium swallow is seen in:", options:["Oesophageal carcinoma","Hypertrophic pyloric stenosis","Duodenal atresia","Achalasia cardia"], answer:1, explanation:"String sign: thin stream of barium through the pylorus on barium meal in hypertrophic pyloric stenosis (HPS). Also seen on ultrasound as elongated pyloric channel." },
  { id:5041, subject:"Medicine", stem:"Serum-ascites albumin gradient (SAAG) >1.1 g/dL indicates:", options:["Exudative ascites (TB peritonitis)","Portal hypertension","Malignant ascites","Pancreatitis"], answer:1, explanation:"SAAG >1.1 g/dL indicates portal hypertension (liver cirrhosis, right heart failure, Budd-Chiari). SAAG <1.1 g/dL suggests exudative causes (TB, malignancy, pancreatitis)." },
  { id:5042, subject:"Medicine", stem:"Whipple's triad in insulinoma consists of:", options:["Fasting hypoglycaemia + symptoms relieved by glucose + symptoms with fasting","Episodic hypertension + headache + sweating","Abdominal pain + diarrhoea + weight loss","Jaundice + fever + right upper quadrant pain"], answer:0, explanation:"Whipple's triad: symptomatic hypoglycaemia during fasting, blood glucose <50 mg/dL during attack, symptoms relieved by glucose administration." },
  { id:5043, subject:"Medicine", stem:"Diagnosis of Helicobacter pylori is BEST confirmed during active PPI therapy using:", options:["Urea breath test","Rapid urease test on biopsy","Serology (IgG)","Stool antigen test"], answer:3, explanation:"Stool antigen test can be done on PPI therapy (with reduced sensitivity). Urea breath test and rapid urease test require stopping PPI for 2 weeks as PPIs cause false negatives." },
  { id:5044, subject:"Medicine", stem:"Most common extraintestinal manifestation of Crohn's disease that does NOT correlate with bowel activity is:", options:["Peripheral arthropathy","Ankylosing spondylitis/sacroiliitis","Erythema nodosum","Uveitis (anterior)"], answer:1, explanation:"Ankylosing spondylitis/sacroiliitis in IBD runs an independent course (not correlated with gut activity). Most other extraintestinal manifestations (arthropathy, EN, uveitis) correlate with disease activity." },
  { id:5045, subject:"Medicine", stem:"'Lead pipe' appearance on barium enema is seen in:", options:["Crohn's disease","Ulcerative colitis","Carcinoma colon","Diverticular disease"], answer:1, explanation:"Lead pipe colon on barium enema: loss of haustra, tubular rigid colon in long-standing ulcerative colitis due to chronic inflammation and fibromuscular thickening." },
  { id:5046, subject:"Medicine", stem:"Hepatitis E is most dangerous in:", options:["Children under 5 years","Immunocompromised patients","Pregnant women (3rd trimester)","Elderly males"], answer:2, explanation:"Hepatitis E causes fulminant hepatic failure in up to 20-25% of pregnant women in the third trimester, with high maternal and foetal mortality." },
  { id:5047, subject:"Medicine", stem:"Anti-smooth muscle antibody (ASMA) is positive in:", options:["Primary biliary cholangitis","Autoimmune hepatitis type 1","Wilson's disease","Haemochromatosis"], answer:1, explanation:"Autoimmune hepatitis type 1: anti-smooth muscle antibody (ASMA) + ANA positive. Type 2: anti-LKM1 (liver-kidney microsomal) antibody. Primary biliary cholangitis: AMA positive." },
  { id:5048, subject:"Medicine", stem:"Kayser-Fleischer rings in Wilson's disease are deposits of:", options:["Iron in the cornea","Copper in Descemet's membrane of cornea","Calcium in lens","Copper in lens"], answer:1, explanation:"Kayser-Fleischer rings: golden-brown copper deposits in Descemet's membrane at the periphery of the cornea. Seen in virtually all Wilson's disease with neurological involvement." },
  { id:5049, subject:"Medicine", stem:"TIPS (Transjugular Intrahepatic Portosystemic Shunt) is contraindicated in:", options:["Refractory ascites","Recurrent variceal bleeding","Hepatic encephalopathy","Hepatorenal syndrome"], answer:2, explanation:"Hepatic encephalopathy is a contraindication to TIPS as it bypasses liver detoxification, worsening encephalopathy. TIPS is used for refractory ascites, variceal bleeding, Budd-Chiari." },
  { id:5050, subject:"Medicine", stem:"Most common cause of acute pancreatitis in India is:", options:["Alcohol","Gallstones","Hypertriglyceridaemia","ERCP-induced"], answer:1, explanation:"Gallstones are the most common cause of acute pancreatitis in India and worldwide. Alcohol is the second most common cause (predominant in Western countries)." },

  // ── NEPHROLOGY ──────────────────────────────────────────────────────────────
  { id:5051, subject:"Medicine", stem:"KDIGO 2024 guidelines recommend SGLT2 inhibitors in CKD when eGFR is:", options:["≥60 mL/min/1.73m²","≥20 mL/min/1.73m²","≥45 mL/min/1.73m²","Any eGFR with diabetes"], answer:1, explanation:"KDIGO 2024: SGLT2 inhibitors recommended for all CKD patients (with or without diabetes) if eGFR ≥20 mL/min/1.73m², as they slow CKD progression and reduce CV events." },
  { id:5052, subject:"Medicine", stem:"Gold standard for measuring GFR is:", options:["Serum creatinine","CKD-EPI equation","Inulin clearance","Cystatin C"], answer:2, explanation:"Inulin clearance is the gold standard for GFR measurement (freely filtered, not secreted or reabsorbed). Creatinine clearance overestimates GFR due to tubular secretion of creatinine." },
  { id:5053, subject:"Medicine", stem:"Nephrotic syndrome is characterised by all EXCEPT:", options:["Proteinuria >3.5 g/day","Hypoalbuminaemia","Hypertension and haematuria","Hyperlipidaemia and lipiduria"], answer:2, explanation:"Nephrotic syndrome: proteinuria >3.5 g/day + hypoalbuminaemia + oedema + hyperlipidaemia + lipiduria. Hypertension and haematuria are features of nephritic syndrome." },
  { id:5054, subject:"Medicine", stem:"Most common cause of nephrotic syndrome in adults is:", options:["Minimal change disease","Focal segmental glomerulosclerosis (FSGS)","Membranous nephropathy","Diabetic nephropathy"], answer:3, explanation:"Diabetic nephropathy is the most common cause of nephrotic syndrome in adults globally. Membranous nephropathy is the most common primary cause in adults." },
  { id:5055, subject:"Medicine", stem:"Renal biopsy showing 'wire loop' lesions with sub-endothelial immune deposits is characteristic of:", options:["IgA nephropathy","Lupus nephritis (class IV)","Membranous nephropathy","Post-streptococcal GN"], answer:1, explanation:"Wire loop lesions: large sub-endothelial immune deposits in mesangium and GBM seen in lupus nephritis class III/IV (diffuse proliferative GN) — worst prognosis class." },
  { id:5056, subject:"Medicine", stem:"Indication for urgent dialysis in AKI includes all EXCEPT:", options:["Uraemic pericarditis","Hyperkalaemia refractory to medical treatment","Metabolic acidosis pH <7.1 refractory to bicarbonate","Oliguria <400 mL/day"], answer:3, explanation:"AEIOU indications for dialysis: Acidosis severe, Electrolyte abnormalities (K+), Intoxication, Overload (pulmonary oedema), Uraemia. Oliguria alone is not an absolute indication." },
  { id:5057, subject:"Medicine", stem:"Thin basement membrane disease (benign familial haematuria) is caused by mutations in:", options:["Nephrin gene","COL4A3/COL4A4 (collagen IV genes)","Podocin gene","TRPC6 gene"], answer:1, explanation:"Thin basement membrane nephropathy: autosomal dominant mutations in COL4A3/A4 (collagen IV). Presents with isolated microscopic haematuria, excellent prognosis." },
  { id:5058, subject:"Medicine", stem:"Fanconi syndrome is characterised by generalised proximal tubular dysfunction with:", options:["Hypokalaemia + metabolic alkalosis","Glycosuria + aminoaciduria + phosphaturia + RTA type 2","Hyperkalaemia + metabolic acidosis","Nephrogenic diabetes insipidus"], answer:1, explanation:"Fanconi syndrome: dysfunction of proximal tubule causing wasting of glucose (normoglycaemia), amino acids, phosphate, bicarbonate (RTA type 2), urate, and potassium." },
  { id:5059, subject:"Medicine", stem:"Urine finding most specific for acute tubular necrosis (ATN) is:", options:["WBC casts","Muddy brown granular casts","RBC casts","Hyaline casts"], answer:1, explanation:"Muddy brown granular casts (pigmented granular casts) are the hallmark of ATN, representing sloughed tubular epithelial cells with haemoglobin degradation products." },
  { id:5060, subject:"Medicine", stem:"Alport syndrome is characterised by:", options:["Nephrotic range proteinuria + deafness + haematuria","Haematuria + sensorineural deafness + ocular abnormalities (lenticonus)","Recurrent UTIs + reflux nephropathy","Polycystic kidneys + liver cysts"], answer:1, explanation:"Alport syndrome: X-linked (COL4A5 mutation) or AR (COL4A3/4) nephritis. Triad: persistent haematuria, sensorineural deafness, anterior lenticonus. Progressive to ESRD in males." },

  // ── NEUROLOGY ───────────────────────────────────────────────────────────────
  { id:5061, subject:"Medicine", stem:"Time window for IV alteplase (tPA) thrombolysis in ischaemic stroke is:", options:["Up to 6 hours","Up to 3 hours (extended to 4.5 hours in selected patients)","Up to 12 hours","Up to 24 hours"], answer:1, explanation:"IV alteplase is given within 3 hours of symptom onset (extended to 4.5 hours in selected patients). Mechanical thrombectomy can be done up to 24 hours in eligible patients." },
  { id:5062, subject:"Medicine", stem:"CSF findings in bacterial meningitis show:", options:["Lymphocytic pleocytosis + high protein + normal glucose","Neutrophilic pleocytosis + high protein + very low glucose","Xanthochromia + high RBCs + normal glucose","Clear CSF + normal pressure + oligoclonal bands"], answer:1, explanation:"Bacterial meningitis CSF: turbid, high opening pressure, PMN pleocytosis (>1000 cells/mm³), very low glucose (<40 mg/dL or CSF/serum ratio <0.4), high protein." },
  { id:5063, subject:"Medicine", stem:"Drug of choice for absence seizures that coexist with other generalised seizure types is:", options:["Ethosuximide","Valproate","Lamotrigine","Levetiracetam"], answer:1, explanation:"Valproate is preferred when absence coexists with other seizure types (JME, tonic-clonic). Ethosuximide is DOC for pure absence seizures only." },
  { id:5064, subject:"Medicine", stem:"Lewy body inclusions in Parkinson disease are composed primarily of:", options:["Tau protein","Alpha-synuclein","TDP-43","Beta-amyloid"], answer:1, explanation:"Lewy bodies: eosinophilic intracytoplasmic inclusions in substantia nigra neurons composed primarily of alpha-synuclein and ubiquitin. Dopaminergic neuron loss causes motor features." },
  { id:5065, subject:"Medicine", stem:"Feature that distinguishes Guillain-Barré syndrome (GBS) from other neuropathies is:", options:["Proximal muscle weakness + sensory loss","Ascending paralysis + areflexia + albuminocytological dissociation in CSF","Distal sensorimotor neuropathy","Asymmetric weakness + cranial nerve palsies"], answer:1, explanation:"GBS CSF: albuminocytological dissociation — high protein (>45 mg/dL) with normal cell count (<10 cells/mm³). Ascending paralysis, areflexia. Treatment: IVIG or plasmapheresis." },
  { id:5066, subject:"Medicine", stem:"Most common type of headache disorder globally is:", options:["Migraine","Cluster headache","Tension-type headache","Medication overuse headache"], answer:2, explanation:"Tension-type headache is the most common headache disorder worldwide (prevalence ~40%). Migraine affects ~15% of the population but causes more disability." },
  { id:5067, subject:"Medicine", stem:"Charcot's triad of multiple sclerosis includes:", options:["Ophthalmoplegia + nystagmus + ataxia (intention tremor)","Fever + rigors + jaundice","Ptosis + diplopia + facial palsy","Headache + papilloedema + vomiting"], answer:0, explanation:"Charcot's neurological triad for MS: nystagmus + intention tremor + scanning speech (dysarthria). Not to be confused with Charcot's biliary triad (fever+rigors+jaundice)." },
  { id:5068, subject:"Medicine", stem:"Myasthenia gravis is diagnosed by all EXCEPT:", options:["Tensilon (edrophonium) test","Anti-AChR antibodies","Ice pack test (for ptosis)","Serum creatine kinase (CK) level"], answer:3, explanation:"MG diagnosis: anti-AChR antibodies (80-85%), tensilon test (improvement with edrophonium), ice pack test, repetitive nerve stimulation (decremental response). CK is elevated in myopathies, not MG." },
  { id:5069, subject:"Medicine", stem:"Todd's paralysis after a generalised tonic-clonic seizure is:", options:["Permanent hemiplegia indicating stroke","Transient focal weakness lasting minutes to hours post-ictally","Absence status epilepticus","Pre-ictal focal weakness"], answer:1, explanation:"Todd's paralysis: transient (minutes to 36 hours) focal neurological deficit (weakness, speech difficulty) after a focal or generalised seizure. Indicates prior cortical involvement of that region." },
  { id:5070, subject:"Medicine", stem:"Drug of choice for trigeminal neuralgia is:", options:["Amitriptyline","Carbamazepine","Pregabalin","Phenytoin"], answer:1, explanation:"Carbamazepine is first-line for trigeminal neuralgia — blocks sodium channels, reduces repetitive neuronal firing. Oxcarbazepine and gabapentin are alternatives." },

  // ── ENDOCRINOLOGY ───────────────────────────────────────────────────────────
  { id:5071, subject:"Medicine", stem:"ADA 2024 preferred agents in diabetes with established cardiovascular disease are:", options:["Metformin + Sulphonylurea","GLP-1 receptor agonist + SGLT2 inhibitor","DPP-4 inhibitor + Insulin","Metformin + TZD"], answer:1, explanation:"ADA 2024: in T2DM with established CVD, ASCVD risk, HF, or CKD — GLP-1 RA (semaglutide reduces MACE) and SGLT2i (reduces HF hospitalisation + CKD progression) are preferred." },
  { id:5072, subject:"Medicine", stem:"HbA1c target for most non-pregnant adults with T2DM is:", options:["<6.0%","<7.0%","<8.0%","<9.0%"], answer:1, explanation:"ADA target: HbA1c <7.0% for most adults. Less stringent (<8%) for elderly, limited life expectancy, severe hypoglycaemia unawareness. More stringent (<6.5%) if safely achievable." },
  { id:5073, subject:"Medicine", stem:"Most sensitive test for primary hypothyroidism is:", options:["Free T4","Free T3","TSH (thyroid stimulating hormone)","Anti-TPO antibody"], answer:2, explanation:"TSH is the most sensitive test for primary thyroid dysfunction. In subclinical hypothyroidism: TSH elevated but T4 normal. TSH is elevated early before T4 falls." },
  { id:5074, subject:"Medicine", stem:"Pretibial myxoedema is seen in:", options:["Hypothyroidism","Graves' disease (hyperthyroidism)","Hashimoto's thyroiditis","Subacute thyroiditis"], answer:1, explanation:"Pretibial myxoedema (localised myxoedema): non-pitting skin thickening over shins, seen in Graves' disease (autoimmune hyperthyroidism). Along with exophthalmos and acropachy = Merseburg triad." },
  { id:5075, subject:"Medicine", stem:"Low-dose dexamethasone suppression test is used to screen for:", options:["Addison's disease","Cushing's syndrome","Primary hyperaldosteronism","Phaeochromocytoma"], answer:1, explanation:"Overnight 1 mg dexamethasone suppression test: cortisol <50 nmol/L at 8 AM rules out Cushing's syndrome. Failure to suppress suggests hypercortisolism." },
  { id:5076, subject:"Medicine", stem:"Best test to distinguish adrenal from pituitary Cushing's is:", options:["24-hour urinary cortisol","High-dose dexamethasone suppression test","Serum ACTH level","MRI pituitary"], answer:1, explanation:"High-dose dexamethasone (8 mg) suppresses ACTH from pituitary (Cushing's disease) but NOT from ectopic sources or adrenal adenoma. ACTH level helps: low in adrenal, high in ectopic." },
  { id:5077, subject:"Medicine", stem:"Phaeochromocytoma triad consists of:", options:["Hypertension + headache + palpitations + sweating","Weight loss + exophthalmos + goitre","Flushing + diarrhoea + bronchospasm","Obesity + hypertension + glucose intolerance"], answer:0, explanation:"Phaeochromocytoma classic triad: episodic headache + sweating + palpitations (catecholamine excess), with hypertension (sustained or paroxysmal). Diagnosis: urinary metanephrines." },
  { id:5078, subject:"Medicine", stem:"Chvostek's and Trousseau's signs indicate:", options:["Hyperkalaemia","Hypocalcaemia","Hypomagnesaemia","Hypophosphataemia"], answer:1, explanation:"Chvostek's (facial twitch on tapping facial nerve) and Trousseau's (carpal spasm with BP cuff) signs indicate hypocalcaemia due to neuromuscular excitability." },
  { id:5079, subject:"Medicine", stem:"Multiple endocrine neoplasia type 1 (MEN-1) comprises:", options:["Medullary thyroid carcinoma + phaeochromocytoma + parathyroid hyperplasia","Parathyroid hyperplasia + pituitary tumour + pancreatic islet cell tumour","Parathyroid + phaeochromocytoma + thyroid","Carcinoid + gastrinoma + insulinoma"], answer:1, explanation:"MEN-1 (Wermer's syndrome): parathyroid hyperplasia (most common, 95%) + pituitary tumours (prolactinoma most common) + pancreatic islet cell tumours (gastrinoma, insulinoma). Gene: MEN1 (menin)." },
  { id:5080, subject:"Medicine", stem:"SIADH (syndrome of inappropriate ADH) causes:", options:["Hypernatraemia with raised osmolality","Hyponatraemia with low serum osmolality and high urine osmolality","Hypernatraemia with high urine output","Hyponatraemia with raised urine sodium <20 mEq/L"], answer:1, explanation:"SIADH: hyponatraemia (serum Na <135) + low plasma osmolality (<275) + inappropriately high urine osmolality (>100) + urine Na >20 mEq/L. Causes: lung cancer, CNS disease, drugs." },

  // ── RHEUMATOLOGY ────────────────────────────────────────────────────────────
  { id:5081, subject:"Medicine", stem:"Revised ACR/EULAR 2019 classification criteria for SLE include:", options:["Butterfly rash + arthritis + photosensitivity (≥3 criteria)","Scoring system with entry criterion of ANA, requiring ≥10 points from weighted criteria","11 clinical criteria requiring ≥4","ANA + anti-dsDNA + complement alone"], answer:1, explanation:"2019 ACR/EULAR SLE criteria: entry criterion (ANA ≥1:80 on HEp-2 cells), then scoring across 7 clinical and 3 immunological domains. Score ≥10 = SLE classification." },
  { id:5082, subject:"Medicine", stem:"Drug of choice for all stages of SLE is:", options:["Prednisolone","Hydroxychloroquine","Cyclophosphamide","Mycophenolate mofetil"], answer:1, explanation:"Hydroxychloroquine is recommended for ALL SLE patients (unless contraindicated) — reduces flares, organ damage, thrombosis risk, and improves survival." },
  { id:5083, subject:"Medicine", stem:"Acute gout attack is treated with:", options:["Allopurinol","Colchicine within 24 hours, or NSAIDs","Febuxostat","Probenecid"], answer:1, explanation:"Acute gout: colchicine (most effective within 24 hours), NSAIDs, or systemic steroids. Allopurinol/febuxostat (urate-lowering therapy) should NOT be started during acute attack." },
  { id:5084, subject:"Medicine", stem:"HLA-B27 is most strongly associated with:", options:["SLE","Ankylosing spondylitis (>90% positive)","Rheumatoid arthritis","Gout"], answer:1, explanation:"HLA-B27 is present in >90% of ankylosing spondylitis patients (vs 8% of general population). Also associated with reactive arthritis, psoriatic arthritis, IBD-related arthritis." },
  { id:5085, subject:"Medicine", stem:"Anti-CCP (anti-cyclic citrullinated peptide) antibody in rheumatoid arthritis has:", options:["High sensitivity, low specificity","Low sensitivity, very high specificity (>95%)","Equal sensitivity and specificity","Low sensitivity and low specificity"], answer:1, explanation:"Anti-CCP: ~70% sensitive but >95% specific for RA. More specific than rheumatoid factor (RF). Can be positive years before symptoms. Predicts erosive, severe disease." },
  { id:5086, subject:"Medicine", stem:"Antiphospholipid syndrome (APS) is diagnosed by:", options:["Anti-dsDNA + recurrent thrombosis","Lupus anticoagulant or anticardiolipin IgG/IgM on 2 occasions 12 weeks apart + clinical criteria (thrombosis/pregnancy morbidity)","Anti-Sm antibody + livedo reticularis","Anti-β2GPI alone"], answer:1, explanation:"APS diagnosis: clinical criteria (arterial/venous thrombosis OR pregnancy morbidity) PLUS laboratory criteria (lupus anticoagulant, anticardiolipin, or anti-β2GPI on 2 occasions ≥12 weeks apart)." },
  { id:5087, subject:"Medicine", stem:"Raynaud's phenomenon follows the colour sequence:", options:["Red → White → Blue","White (pallor) → Blue (cyanosis) → Red (reperfusion)","Blue → Red → White","Red → Blue → White"], answer:1, explanation:"Raynaud's triphasic colour change: white (pallor, vasospasm) → blue (cyanosis, deoxygenation) → red (reperfusion, reactive hyperaemia). Triggered by cold or stress." },
  { id:5088, subject:"Medicine", stem:"Sicca syndrome (dry eyes + dry mouth) is the hallmark of:", options:["SLE","Sjögren's syndrome","Systemic sclerosis","Myositis"], answer:1, explanation:"Sjögren's syndrome: autoimmune exocrinopathy causing keratoconjunctivitis sicca (dry eyes) + xerostomia (dry mouth). Antibodies: anti-Ro/SSA (most sensitive), anti-La/SSB (specific)." },
  { id:5089, subject:"Medicine", stem:"CREST syndrome is a limited form of:", options:["SLE","Systemic sclerosis (scleroderma)","RA","Sjögren's syndrome"], answer:1, explanation:"CREST: Calcinosis + Raynaud's + oEsophageal dysmotility + Sclerodactyly + Telangiectasia = limited systemic sclerosis. Anti-centromere antibody is characteristic." },
  { id:5090, subject:"Medicine", stem:"Muscle enzyme most elevated in polymyositis/dermatomyositis is:", options:["AST","LDH","Creatine kinase (CK)","Aldolase"], answer:2, explanation:"CK is the most sensitive and commonly used marker for muscle inflammation in myositis. CK can be elevated 10-50× normal. Anti-Jo-1 antibody is the most common myositis-specific antibody." },

  // ── HAEMATOLOGY ─────────────────────────────────────────────────────────────
  { id:5091, subject:"Medicine", stem:"MCV <70 fL with low serum ferritin is most consistent with:", options:["Thalassaemia minor","Iron deficiency anaemia","Anaemia of chronic disease","Sideroblastic anaemia"], answer:1, explanation:"Iron deficiency anaemia: microcytic (MCV <80 fL, often <70), hypochromic, low serum ferritin (most specific test), low serum iron, high TIBC, low transferrin saturation." },
  { id:5092, subject:"Medicine", stem:"Philadelphia chromosome (t(9;22)) is the hallmark of:", options:["AML","ALL (paediatric)","CML","Multiple myeloma"], answer:2, explanation:"Philadelphia chromosome: t(9;22) translocation producing BCR-ABL fusion gene (constitutively active tyrosine kinase). Hallmark of CML; also found in 20-30% of adult ALL (poor prognosis)." },
  { id:5093, subject:"Medicine", stem:"Reed-Sternberg cells are pathognomonic of:", options:["Non-Hodgkin's lymphoma","Hodgkin's lymphoma","CLL","Infectious mononucleosis"], answer:1, explanation:"Reed-Sternberg cells: large binucleate/multinucleate cells with 'owl-eye' nucleoli — pathognomonic of Hodgkin's lymphoma. CD15+, CD30+ by immunohistochemistry." },
  { id:5094, subject:"Medicine", stem:"Serum protein electrophoresis showing M-spike (paraprotein) is characteristic of:", options:["CML","Multiple myeloma","Iron deficiency","Polycythaemia vera"], answer:1, explanation:"Multiple myeloma: monoclonal gammopathy causing M-spike on SPEP (usually IgG or IgA). Bence Jones proteins (free light chains) in urine. Diagnostic: bone marrow plasma cells >10%." },
  { id:5095, subject:"Medicine", stem:"Peripheral smear showing 'teardrop cells' (dacrocytes) with extramedullary haematopoiesis suggests:", options:["Iron deficiency anaemia","Myelofibrosis (primary/secondary)","Hereditary spherocytosis","G6PD deficiency"], answer:1, explanation:"Myelofibrosis: bone marrow replaced by fibrotic tissue → extramedullary haematopoiesis (splenomegaly, hepatomegaly) → teardrop cells on smear. JAK2 mutation in 50-60%." },
  { id:5096, subject:"Medicine", stem:"DIC (disseminated intravascular coagulation) is characterised by:", options:["Elevated PT, elevated APTT, low fibrinogen, low platelets, elevated D-dimer","Low PT, low APTT, high fibrinogen, high platelets","Elevated APTT only with normal PT","Normal PT, normal APTT with low platelets"], answer:0, explanation:"DIC: consumption of clotting factors and platelets — elevated PT, elevated APTT, low fibrinogen, thrombocytopenia, elevated D-dimer (fibrin degradation products), elevated FDP." },
  { id:5097, subject:"Medicine", stem:"Osmotic fragility test is increased (red cells lyse at higher NaCl concentrations) in:", options:["G6PD deficiency","Sickle cell anaemia","Hereditary spherocytosis","Iron deficiency"], answer:2, explanation:"Hereditary spherocytosis: spherical RBCs with reduced surface-to-volume ratio → increased osmotic fragility (lyse at higher saline concentrations). Coombs' negative, MCHC increased." },
  { id:5098, subject:"Medicine", stem:"Cobalamin (B12) deficiency causes neurological damage due to deficiency of:", options:["Myelin basic protein synthesis","Methylmalonyl-CoA mutase → accumulation of methylmalonate (neurotoxic)","GABA synthesis","Dopamine synthesis"], answer:1, explanation:"B12 deficiency: impaired methylmalonyl-CoA mutase causes methylmalonate accumulation, damaging myelin (subacute combined degeneration of cord). Also impairs methionine synthesis." },
  { id:5099, subject:"Medicine", stem:"Most common cause of thrombocytopenia in hospitalised patients is:", options:["ITP","Heparin-induced thrombocytopenia (HIT)","Drug-induced thrombocytopenia","Sepsis/DIC"], answer:3, explanation:"Sepsis-associated thrombocytopenia (from consumption, bone marrow suppression, splenic sequestration) is the most common cause in hospitalised ICU patients." },
  { id:5100, subject:"Medicine", stem:"Polycythaemia vera is distinguished from secondary polycythaemia by:", options:["Haematocrit >52%","JAK2 V617F mutation + low serum EPO + splenomegaly + raised WBC/platelets","Raised EPO + normal WBC/platelets","Cyanosis + clubbing"], answer:1, explanation:"PV: JAK2 V617F mutation (>95%), low serum erythropoietin (autonomous production), splenomegaly, raised WBC and platelets. Secondary polycythaemia has HIGH EPO." },

  // ── INFECTIOUS DISEASE ──────────────────────────────────────────────────────
  { id:5101, subject:"Medicine", stem:"First-line antiretroviral regimen for all adults with HIV per NACO 2021 guidelines is:", options:["Zidovudine + Lamivudine + Nevirapine (ZLN)","Tenofovir + Lamivudine + Dolutegravir (TLD)","Abacavir + Lamivudine + Efavirenz","Tenofovir + Emtricitabine + Lopinavir/ritonavir"], answer:1, explanation:"NACO 2021: TLD (Tenofovir 300mg + Lamivudine 300mg + Dolutegravir 50mg) as first-line for all adults — high barrier to resistance, fewer side effects than previous regimens." },
  { id:5102, subject:"Medicine", stem:"CD4 count below which Pneumocystis jirovecii pneumonia (PCP) prophylaxis should be started is:", options:["<500 cells/μL","<350 cells/μL","<200 cells/μL","<100 cells/μL"], answer:2, explanation:"PCP prophylaxis (co-trimoxazole) started when CD4 <200 cells/μL in HIV. CMV retinitis prophylaxis: CD4 <50. Toxoplasma prophylaxis: CD4 <100 (if Toxo IgG positive)." },
  { id:5103, subject:"Medicine", stem:"Weil's disease (severe leptospirosis) is characterised by:", options:["Rash + lymphadenopathy + hepatosplenomegaly","Jaundice + acute renal failure + haemorrhage","Ascending paralysis + respiratory failure","Fever + rose spots + relative bradycardia"], answer:1, explanation:"Weil's disease (icterohemorrhagic leptospirosis): jaundice + acute renal failure (oliguric AKI) + haemorrhagic manifestations. Caused by Leptospira interrogans. Treated with penicillin/doxycycline." },
  { id:5104, subject:"Medicine", stem:"Dengue haemorrhagic fever (DHF) is diagnosed when dengue fever is accompanied by:", options:["Rash alone","Thrombocytopenia (<100,000/μL) + evidence of plasma leakage (haematocrit rise ≥20%)","Fever + myalgia + positive NS1 antigen","Any dengue with bleeding"], answer:1, explanation:"DHF requires: dengue fever + thrombocytopenia ≤100,000/μL + haemoconcentration (haematocrit rise ≥20%) or other evidence of plasma leakage (pleural effusion, ascites)." },
  { id:5105, subject:"Medicine", stem:"Typhoid fever is confirmed by:", options:["Widal test titre >1:160","Blood culture (gold standard), especially in first week","Stool culture in first week","Urine culture"], answer:1, explanation:"Blood culture is gold standard for typhoid — positive in 80% in first week. Bone marrow culture is most sensitive overall (90%). Widal test is only supportive (many false positives in endemic areas)." },
  { id:5106, subject:"Medicine", stem:"Drug of choice for uncomplicated falciparum malaria in India is:", options:["Chloroquine","Primaquine","Artemether-lumefantrine (AL)","Quinine + Doxycycline"], answer:2, explanation:"Artemether-lumefantrine (AL) is WHO/NVBDCP-recommended ACT for uncomplicated P. falciparum malaria. Chloroquine resistance is widespread in falciparum." },
  { id:5107, subject:"Medicine", stem:"Rose spots in typhoid fever are:", options:["Petechiae on lower limbs","Salmon-pink maculopapular rash on trunk/abdomen (2-4 mm, fade with pressure)","Purpuric rash on face","Erythematous rash with central clearing"], answer:1, explanation:"Rose spots: 2-4 mm salmon-pink maculopapular lesions on the trunk/abdomen, appearing in crops during the 2nd week of typhoid fever. They fade on pressure." },
  { id:5108, subject:"Medicine", stem:"Relative bradycardia (Faget's sign) — pulse not proportionally raised for temperature — is seen in:", options:["Septic shock","Typhoid fever","Bacterial meningitis","Dengue fever"], answer:1, explanation:"Relative bradycardia (Faget's sign): pulse not proportionally elevated for the degree of fever. Classically described in typhoid fever, also seen in yellow fever, brucellosis." },
  { id:5109, subject:"Medicine", stem:"Treatment of choice for Pneumocystis jirovecii pneumonia (PCP) in HIV is:", options:["Fluconazole","High-dose Co-trimoxazole (TMP-SMX) for 21 days + adjunctive corticosteroids if PaO2 <70 mmHg","Caspofungin","Amphotericin B"], answer:1, explanation:"PCP treatment: high-dose TMP-SMX (15-20 mg/kg/day of TMP component) for 21 days. Adjunctive steroids for moderate-severe PCP (PaO2 <70 mmHg) improve survival." },
  { id:5110, subject:"Medicine", stem:"Jarisch-Herxheimer reaction occurs after treatment of:", options:["Malaria","Syphilis (and other spirochaetal infections)","PCP","Candidiasis"], answer:1, explanation:"Jarisch-Herxheimer reaction: fever, chills, rigors within 2-8 hours of antibiotic treatment for spirochaetal infections (syphilis, leptospirosis, Lyme disease) — due to cytokine release from dying organisms." },

  // ── CRITICAL CARE ───────────────────────────────────────────────────────────
  { id:5111, subject:"Medicine", stem:"Surviving Sepsis Campaign 2021 bundle — what must be done within 1 hour of sepsis recognition?", options:["Blood cultures → broad-spectrum antibiotics → 30 mL/kg crystalloid → vasopressors → lactate measurement","Blood cultures alone, then antibiotics within 3 hours","ICU transfer before any intervention","Corticosteroids immediately"], answer:0, explanation:"SSC Hour-1 bundle: measure lactate, obtain blood cultures BEFORE antibiotics, administer broad-spectrum antibiotics, 30 mL/kg crystalloid for hypoperfusion, vasopressors if hypotensive." },
  { id:5112, subject:"Medicine", stem:"First-line vasopressor in septic shock is:", options:["Adrenaline (epinephrine)","Noradrenaline (norepinephrine)","Vasopressin","Dopamine"], answer:1, explanation:"Noradrenaline (norepinephrine) is the first-line vasopressor in septic shock (SSC 2021). Vasopressin can be added as second agent. Adrenaline reserved for anaphylaxis or refractory shock." },
  { id:5113, subject:"Medicine", stem:"ARDS (acute respiratory distress syndrome) Berlin definition requires:", options:["PaO2/FiO2 <300 + bilateral chest infiltrates + PCWP >18 mmHg","Acute onset within 1 week + bilateral opacities on CXR + PaO2/FiO2 <300 + not explained by cardiac failure","SpO2 <90% + bilateral infiltrates","Any respiratory failure requiring intubation"], answer:1, explanation:"Berlin ARDS criteria: acute onset (≤1 week) + bilateral opacities (not fully explained by effusion/collapse/nodules) + PaO2/FiO2 <300 (on PEEP≥5) + not cardiac oedema as primary cause." },
  { id:5114, subject:"Medicine", stem:"Lung-protective ventilation strategy in ARDS uses:", options:["High tidal volumes (10-12 mL/kg IBW) + low PEEP","Low tidal volumes (6 mL/kg IBW) + high PEEP + target plateau pressure <30 cmH2O","Prone positioning alone","Pressure control ventilation with FiO2 1.0"], answer:1, explanation:"ARDSNet protocol: tidal volume 6 mL/kg ideal body weight, plateau pressure <30 cmH2O, higher PEEP table guided by FiO2. Reduced 28-day mortality by 22% vs conventional ventilation." },
  { id:5115, subject:"Medicine", stem:"Most common acid-base disorder in patients on mechanical ventilation (over-ventilated) is:", options:["Metabolic alkalosis","Respiratory alkalosis","Metabolic acidosis","Respiratory acidosis"], answer:1, explanation:"Respiratory alkalosis is common in over-ventilated patients — excessive CO2 elimination lowers PaCO2 (<35 mmHg), raising pH. Causes cerebral vasoconstriction, tetany." },

  // ── MIXED HIGH-YIELD ─────────────────────────────────────────────────────────
  { id:5116, subject:"Medicine", stem:"Target blood pressure in hypertensive emergency with hypertensive encephalopathy:", options:["Normalise BP immediately to <120/80","Reduce MAP by 25% in first hour, then to 160/100 over next 2-6 hours","Reduce by 50% in first 30 minutes","Keep SBP 180-200 for first 24 hours"], answer:1, explanation:"Hypertensive emergency: reduce MAP by no more than 25% in first hour (risk of ischaemia). Target BP 160/100 in next 2-6 hours. Use IV labetalol, nicardipine, or nitroprusside." },
  { id:5117, subject:"Medicine", stem:"Zika virus in pregnancy most commonly causes:", options:["Hydrops fetalis","Microcephaly in the foetus","Placental abruption","Congenital heart defects"], answer:1, explanation:"Zika virus (flavivirus, Aedes mosquito) can cross placenta, preferentially infecting neural progenitor cells causing microcephaly and other brain abnormalities in the foetus." },
  { id:5118, subject:"Medicine", stem:"Correct interpretation of a sensitivity of 90% and specificity of 85% for a test:", options:["10% false positives and 15% false negatives","90% of those WITH disease will test positive; 85% of those WITHOUT disease will test negative","90% of positive tests are true positives","Test correctly classifies 87.5% of all patients"], answer:1, explanation:"Sensitivity = % of true positives (disease present, test positive). Specificity = % of true negatives (disease absent, test negative). Does not measure the predictive value of the test result." },
  { id:5119, subject:"Medicine", stem:"Erythema chronicum migrans (bull's-eye rash) is pathognomonic of:", options:["Rocky Mountain spotted fever","Lyme disease (Borrelia burgdorferi)","Ehrlichiosis","Southern tick-associated rash illness"], answer:1, explanation:"Erythema migrans: expanding annular erythematous rash with central clearing, beginning at tick bite site — pathognomonic of Lyme disease. Clinical diagnosis; treat with doxycycline." },
  { id:5120, subject:"Medicine", stem:"Conn's syndrome (primary hyperaldosteronism) presents with:", options:["Hyperkalaemia + metabolic acidosis","Hypokalaemia + hypertension + metabolic alkalosis","Hyponatraemia + hyperkalaemia + hypotension","Hyperkalaemia + hypertension"], answer:1, explanation:"Conn's syndrome: autonomous aldosterone secretion → Na retention (hypertension), K wasting (hypokalaemia), H+ wasting (metabolic alkalosis). Screening: aldosterone:renin ratio >30." },
  { id:5121, subject:"Medicine", stem:"Which diuretic causes hypokalaemia, hypocalcaemia, and hypomagnesaemia?", options:["Spironolactone","Thiazide diuretics","Loop diuretics (furosemide)","Acetazolamide"], answer:2, explanation:"Loop diuretics (furosemide): inhibit Na-K-2Cl cotransporter in thick ascending loop → wasting of K, Mg, Ca (hypocalcaemia). Thiazides cause hypercalcaemia (increased reabsorption)." },
  { id:5122, subject:"Medicine", stem:"Syndrome of pellagra is caused by deficiency of:", options:["Thiamine (B1)","Niacin (B3) or tryptophan","Pyridoxine (B6)","Riboflavin (B2)"], answer:1, explanation:"Pellagra (B3/niacin deficiency): 4 Ds — Dermatitis (Casal's necklace), Diarrhoea, Dementia, Death. Common in maize-eating populations; also seen in carcinoid syndrome (tryptophan consumption)." },
  { id:5123, subject:"Medicine", stem:"Erythrocyte sedimentation rate (ESR) is FALSELY LOW in:", options:["Pregnancy","Sickle cell anaemia (abnormal shape prevents rouleaux)","Infection","Multiple myeloma"], answer:1, explanation:"ESR is falsely low in sickle cell anaemia (abnormal RBC shape prevents rouleaux formation), polycythaemia (too many cells), congestive cardiac failure." },
  { id:5124, subject:"Medicine", stem:"Yellow fever vaccine is a:", options:["Killed whole-cell vaccine","Live attenuated vaccine (17D strain)","Recombinant subunit vaccine","Toxoid vaccine"], answer:1, explanation:"Yellow fever vaccine (17D strain): live attenuated vaccine, given SC as single dose. Provides immunity >10 years (likely lifelong). Required for international travel to endemic areas." },
  { id:5125, subject:"Medicine", stem:"Addisonian crisis (acute adrenal insufficiency) treatment priority is:", options:["Oral fludrocortisone immediately","IV hydrocortisone 100 mg bolus + aggressive IV saline resuscitation","IV ACTH stimulation test before treatment","Oral prednisolone 40 mg"], answer:1, explanation:"Addisonian crisis: IV hydrocortisone 100 mg bolus immediately (acts as both glucocorticoid and mineralocorticoid at high dose) + aggressive IV 0.9% saline resuscitation. Do NOT delay treatment for tests." },
  { id:5126, subject:"Medicine", stem:"Most common cause of community-acquired pneumonia (CAP) requiring hospitalisation is:", options:["Staphylococcus aureus","Streptococcus pneumoniae","Haemophilus influenzae","Legionella pneumophila"], answer:1, explanation:"Streptococcus pneumoniae is the most common cause of CAP in all age groups requiring hospitalisation worldwide. Legionella is associated with atypical/severe CAP." },
  { id:5127, subject:"Medicine", stem:"Osler-Weber-Rendu syndrome (hereditary haemorrhagic telangiectasia) typically presents with:", options:["Haemoptysis + clubbing","Recurrent epistaxis + mucocutaneous telangiectasias + arteriovenous malformations","Rectal bleeding + colonic polyps","Petechiae + joint bleeds"], answer:1, explanation:"HHT (Osler-Weber-Rendu): autosomal dominant, mutations in endoglin or ALK1. Recurrent epistaxis (most common), mucocutaneous telangiectasias, pulmonary/hepatic/cerebral AVMs." },
  { id:5128, subject:"Medicine", stem:"The most common electrolyte abnormality in patients with chronic liver disease is:", options:["Hyperkalaemia","Hyponatraemia (dilutional)","Hypercalcaemia","Hyperphosphataemia"], answer:1, explanation:"Hyponatraemia (dilutional) is the most common electrolyte abnormality in cirrhosis — caused by ADH release from non-osmotic stimuli (reduced effective blood volume) causing water retention." },
  { id:5129, subject:"Medicine", stem:"Mechanism of action of colchicine in acute gout is:", options:["Xanthine oxidase inhibition","Inhibition of tubulin polymerisation → impairs neutrophil migration and phagocytosis","Uricosuric effect","COX-2 inhibition"], answer:1, explanation:"Colchicine binds tubulin, inhibiting microtubule polymerisation → impairs neutrophil chemotaxis, phagocytosis, and degranulation. Highly effective within 24 hours of gout attack." },
  { id:5130, subject:"Medicine", stem:"Drug of choice for hereditary angioedema (C1-esterase inhibitor deficiency) acute attack is:", options:["Adrenaline IM","C1 inhibitor concentrate or icatibant (bradykinin B2 receptor antagonist)","Antihistamines","Steroids"], answer:1, explanation:"HAE is mediated by bradykinin (not histamine), so antihistamines and steroids are ineffective. Treatment: C1-INH concentrate, icatibant (bradykinin B2 antagonist), or tranexamic acid." },
  { id:5131, subject:"Medicine", stem:"'Bamboo spine' on X-ray is the hallmark of:", options:["Rheumatoid arthritis","Ankylosing spondylitis","Psoriatic arthritis","Diffuse idiopathic skeletal hyperostosis (DISH)"], answer:1, explanation:"Bamboo spine: fusion of the vertebral column from calcification of paravertebral ligaments and syndesmophytes, seen in advanced ankylosing spondylitis on X-ray/MRI." },
  { id:5132, subject:"Medicine", stem:"Wernicke's encephalopathy (thiamine deficiency) classic triad is:", options:["Ophthalmoplegia + ataxia + confusion","Headache + vomiting + papilloedema","Psychosis + peripheral neuropathy + pellagra","Tremor + rigidity + bradykinesia"], answer:0, explanation:"Wernicke's triad: ophthalmoplegia (nystagmus, lateral rectus palsy), ataxia (cerebellar), confusion. Treat with IV thiamine BEFORE glucose. Progression: Korsakoff psychosis (permanent memory loss)." },
  { id:5133, subject:"Medicine", stem:"Coeliac disease antibody most specific for diagnosis is:", options:["Anti-gliadin IgA","Anti-endomysial IgA (EMA)","Anti-tissue transglutaminase IgA (anti-tTG)","Anti-reticulin IgA"], answer:2, explanation:"Anti-tTG IgA: most used (high sensitivity and specificity); anti-EMA IgA: most specific (>99%) but operator-dependent. Gold standard for diagnosis: duodenal biopsy (villous atrophy + crypt hyperplasia)." },
  { id:5134, subject:"Medicine", stem:"Hyperosmolar hyperglycaemic state (HHS) differs from DKA by:", options:["HHS has ketonuria; DKA does not","HHS: glucose >600 mg/dL, osmolality >320, no significant ketosis/acidosis; seen in T2DM","HHS is more common in T1DM","HHS has lower glucose than DKA"], answer:1, explanation:"HHS: glucose >600 mg/dL, plasma osmolality >320 mOsm/kg, minimal ketonuria/acidosis, occurs in T2DM (residual insulin prevents lipolysis/ketogenesis). Mortality higher than DKA." },
  { id:5135, subject:"Medicine", stem:"Most common opportunistic infection in HIV patients in India is:", options:["PCP","Toxoplasmosis","Tuberculosis","CMV retinitis"], answer:2, explanation:"Tuberculosis (both pulmonary and extrapulmonary) is the most common opportunistic infection in HIV-positive patients in India, occurring at any CD4 count." },
  { id:5136, subject:"Medicine", stem:"Haemochromatosis is associated with which genetic mutation?", options:["BRCA1","HFE gene (C282Y mutation, chromosome 6)","CFTR gene","APC gene"], answer:1, explanation:"Hereditary haemochromatosis: most commonly caused by HFE gene C282Y homozygous mutation (autosomal recessive). Causes iron overload → liver cirrhosis, cardiomyopathy, diabetes, bronze skin, arthropathy." },
  { id:5137, subject:"Medicine", stem:"Which malaria species causes 'tertian' fever with a 48-hour cycle?", options:["P. malariae","P. ovale and P. vivax","P. falciparum","P. knowlesi"], answer:1, explanation:"Tertian malaria (fever every 48 hours): P. vivax and P. ovale. P. malariae causes quartan fever (72 hours). P. falciparum causes irregular/continuous fever (most dangerous species)." },
  { id:5138, subject:"Medicine", stem:"Anti-GBM (anti-glomerular basement membrane) antibody disease (Goodpasture syndrome) causes:", options:["Nephrotic syndrome + haematuria","Rapidly progressive GN + pulmonary haemorrhage","Chronic GN + deafness","Recurrent UTIs"], answer:1, explanation:"Goodpasture syndrome: anti-GBM antibodies target alpha-3 chain of type IV collagen in GBM and lung alveolar BM → rapidly progressive GN (crescentic) + pulmonary haemorrhage." },
  { id:5139, subject:"Medicine", stem:"Zollinger-Ellison syndrome is caused by:", options:["H. pylori infection of antrum","Gastrin-secreting tumour (gastrinoma) → severe peptic ulceration","VIPoma secreting vasoactive intestinal peptide","Glucagonoma"], answer:1, explanation:"Zollinger-Ellison: gastrinoma (usually in gastrinoma triangle) secreting excess gastrin → gastric acid hypersecretion → severe, multiple, atypical peptic ulcers. Diagnose with fasting gastrin level." },
  { id:5140, subject:"Medicine", stem:"Haemodialysis vs peritoneal dialysis: peritoneal dialysis is preferred in:", options:["Haemodynamically unstable patients","Children + patients with vascular access problems + diabetics with autonomic neuropathy","Patients with peritoneal adhesions","Patients requiring rapid solute clearance"], answer:1, explanation:"Peritoneal dialysis: preferred in children (better growth), patients lacking vascular access, diabetics (continuous insulin delivery), haemodynamically stable patients preferring home therapy." },

  // ── MORE HIGH-YIELD MEDICINE ─────────────────────────────────────────────────
  { id:5141, subject:"Medicine", stem:"Osmostat reset is a form of:", options:["SIADH","Psychogenic polydipsia","Physiological hyponatraemia (pregnancy, elderly)","Diabetes insipidus"], answer:0, explanation:"Reset osmostat: SIADH variant where osmoregulatory system is reset to a lower threshold. Characterised by stable (not worsening) hyponatraemia with appropriate response to osmotic challenge." },
  { id:5142, subject:"Medicine", stem:"'Bull's neck' appearance in diphtheria is due to:", options:["Cervical lymphadenopathy + soft tissue oedema","Retropharyngeal abscess","Epiglottitis","Ludwig's angina"], answer:0, explanation:"Bull's neck in diphtheria: caused by cervical lymphadenopathy and marked submandibular/neck soft tissue oedema. Caused by Corynebacterium diphtheriae exotoxin (membrane formation + systemic toxin)." },
  { id:5143, subject:"Medicine", stem:"Erythema marginatum rash is associated with:", options:["SLE","Rheumatic fever (Jones major criterion)","Lyme disease","Systemic sclerosis"], answer:1, explanation:"Erythema marginatum: fleeting, non-pruritic, pink rings with central clearing on trunk — one of the five major Jones criteria for acute rheumatic fever." },
  { id:5144, subject:"Medicine", stem:"Drug of choice for cryptococcal meningitis in HIV is:", options:["Fluconazole","Amphotericin B + flucytosine (induction) → fluconazole consolidation","Voriconazole","Caspofungin"], answer:1, explanation:"Cryptococcal meningitis treatment: induction with liposomal amphotericin B + flucytosine for 2 weeks → consolidation with fluconazole 400 mg/day for 8 weeks → maintenance 200 mg/day." },
  { id:5145, subject:"Medicine", stem:"Most common cause of secondary hypertension in young women is:", options:["Renal artery stenosis","Fibromuscular dysplasia of renal artery","Primary hyperaldosteronism","Oral contraceptive pill"], answer:3, explanation:"Oral contraceptive pills (oestrogen-containing) are the most common cause of secondary hypertension in young women — cause renin-angiotensin activation. Stopping OCP usually reverses hypertension." },
  { id:5146, subject:"Medicine", stem:"Pseudogout (calcium pyrophosphate deposition disease) most commonly affects which joint?", options:["First metatarsophalangeal joint","Knee joint (most common)","Shoulder","Small joints of hand"], answer:1, explanation:"Pseudogout: calcium pyrophosphate crystal deposition in articular cartilage. Most commonly affects the knee. X-ray shows chondrocalcinosis. Acute attack resembles gout but at knee/wrist/shoulder." },
  { id:5147, subject:"Medicine", stem:"Serum ferritin is the most useful marker for monitoring in:", options:["Iron deficiency anaemia treatment response","Haemochromatosis and iron overload states","Anaemia of chronic disease","Thalassaemia"], answer:1, explanation:"Serum ferritin is the best marker for monitoring iron stores/overload in haemochromatosis (target <50 μg/L with phlebotomy). In IDA, ferritin is low but rises rapidly with treatment." },
  { id:5148, subject:"Medicine", stem:"Paraneoplastic syndrome of SIADH is most associated with:", options:["Breast cancer","Small cell lung cancer","Colon cancer","Prostate cancer"], answer:1, explanation:"Small cell lung cancer (SCLC) most commonly causes SIADH (ectopic ADH production), Cushing's syndrome (ACTH), Eaton-Lambert syndrome (anti-VGCC), and peripheral neuropathy." },
  { id:5149, subject:"Medicine", stem:"The target LDL-C level in a patient with established coronary artery disease is:", options:["<130 mg/dL","<100 mg/dL","<70 mg/dL","<55 mg/dL (ESC 2021 very high risk)"], answer:3, explanation:"ESC 2021: very high CV risk (established ASCVD) — LDL-C target <55 mg/dL AND ≥50% reduction from baseline. Use high-intensity statin ± ezetimibe ± PCSK9 inhibitor." },
  { id:5150, subject:"Medicine", stem:"Paget's disease of bone (osteitis deformans) characteristically shows:", options:["Alkaline phosphatase elevated + calcium elevated + phosphate low","Markedly elevated serum alkaline phosphatase + normal calcium and phosphate","Low alkaline phosphatase + elevated calcium","Normal ALP with elevated uric acid"], answer:1, explanation:"Paget's disease: markedly elevated alkaline phosphatase (ALP) reflecting excessive osteoclast/osteoblast activity. Calcium and phosphate usually normal. Bone scan: hot spots. Treated with bisphosphonates." },
];
